import 'dart:io'; import 'package:image/image.dart' as img; void main() { final bytes = File('assets/icon.webp').readAsBytesSync(); final image = img.decodeWebP(bytes); if (image == null) return; final cropped = img.copyCrop(image, x: 0, y: 0, width: image.width, height: (image.height * 0.70).toInt()); File('assets/bag_only.png').writeAsBytesSync(img.encodePng(cropped)); print('Cropped successfully.'); }
